const { execSync } = require('child_process');

try {
  const result = execSync("={{ 'python3 /home/clawd/.openclaw/workspace/scripts/kb-search.py \"' + $json.search_plan.search_terms.join(' ') + '\" --limit 20' }}", {
    encoding: 'utf-8',
    timeout: 120000,
    env: { ...process.env, PATH: '/home/clawd/.local/bin:/home/clawd/.npm-global/bin:/usr/local/bin:/usr/bin:/bin:' + process.env.PATH },
    cwd: '/home/clawd'
  });

  return [{ json: { stdout: result, exitCode: 0 } }];
} catch (error) {
  return [{ json: { stdout: error.stdout || '', stderr: error.stderr || error.message, exitCode: error.status || 1 } }];
}

// Parse KB search results into standard source format
const stdout = $input.first().json.stdout || '';
let results = [];

try {
  results = JSON.parse(stdout);
} catch (e) {
  // Falls kb-search.py zeilenweise JSON liefert
  results = stdout.trim().split('\n').filter(Boolean).map(line => {
    try { return JSON.parse(line); } catch { return null; }
  }).filter(Boolean);
}

const sources = results.map(r => ({
  url: r.url || r.path || `kb://local/${r.id || r.title}`,
  title: r.title || r.name || 'KB Result',
  snippet: r.snippet || r.content || r.text || '',
  source_type: 'kb',
  origin: 'kb-search',
  relevance_score: r.score || r.relevance || 0.5,
  tier: 'T2',
  raw: r
}));

return [{ json: { sources, branch: 'kb' } }];

// Merge + deduplicate Brave and Tavily results
const items = $input.all();
const seen = new Set();
const sources = [];

// Brave results
const braveData = items[0]?.json || {};
const braveResults = braveData.web?.results || [];
for (const r of braveResults) {
  const url = r.url;
  if (url && !seen.has(url)) {
    seen.add(url);
    sources.push({
      url,
      title: r.title || '',
      snippet: r.description || '',
      source_type: 'web',
      origin: 'brave',
      relevance_score: 0.5,
      tier: 'T3',
      published_at: r.page_age || null
    });
  }
}

// Tavily results
const tavilyData = items[1]?.json || {};
const tavilyResults = tavilyData.results || [];
for (const r of tavilyResults) {
  const url = r.url;
  if (url && !seen.has(url)) {
    seen.add(url);
    sources.push({
      url,
      title: r.title || '',
      snippet: r.content || '',
      source_type: 'web',
      origin: 'tavily',
      relevance_score: r.score || 0.5,
      tier: 'T3',
      published_at: r.published_date || null
    });
  } else if (url && seen.has(url)) {
    // Boost relevance for sources found by both engines
    const existing = sources.find(s => s.url === url);
    if (existing) {
      existing.relevance_score = Math.min(1.0, existing.relevance_score + 0.2);
      existing.origin = 'brave+tavily';
    }
  }
}

return [{ json: { sources, branch: 'web' } }];

// Filter MiniFlux entries by relevance + extract content
const data = $input.first().json;
const entries = data.entries || [];
const searchTerms = ($input.first().json.search_plan?.keywords || []).map(k => k.toLowerCase());

// Score entries by keyword presence in title + content
const scored = entries.map(entry => {
  const title = (entry.title || '').toLowerCase();
  const content = (entry.content || '').toLowerCase();
  let score = 0;
  for (const term of searchTerms) {
    if (title.includes(term)) score += 0.3;
    if (content.includes(term)) score += 0.1;
  }
  // Normalize to 0-1
  score = Math.min(1.0, score);
  return { entry, score };
}).filter(s => s.score > 0.1)
  .sort((a, b) => b.score - a.score)
  .slice(0, 20);

const sources = scored.map(({ entry, score }) => {
  // Strip HTML tags for snippet
  const plainContent = (entry.content || '').replace(/<[^>]*>/g, '').slice(0, 500);
  return {
    url: entry.url || entry.feed?.site_url || '',
    title: entry.title || '',
    snippet: plainContent,
    source_type: 'rss',
    origin: 'miniflux',
    relevance_score: score,
    tier: 'T3',
    published_at: entry.published_at || null,
    feed_title: entry.feed?.title || '',
    miniflux_entry_id: entry.id
  };
});

return [{ json: { sources, branch: 'rss' } }];

// Deduplication (URL-based), assign source_type and initial tier
const items = $input.all();
const seen = new Map();
const allSources = [];

// Sammle alle Sources aus allen Branches
for (const item of items) {
  const branchSources = item.json.sources || [];
  for (const source of branchSources) {
    const url = source.url;
    if (!url) continue;

    if (seen.has(url)) {
      // Bereits gesehen: Boost relevance, merge origins
      const existing = seen.get(url);
      existing.relevance_score = Math.min(1.0, existing.relevance_score + 0.15);
      if (!existing.origin.includes(source.origin)) {
        existing.origin += '+' + source.origin;
      }
      // Multi-source = hoehere Zuverlaessigkeit
      existing.cross_referenced = true;
    } else {
      const entry = {
        ...source,
        cross_referenced: false
      };
      seen.set(url, entry);
      allSources.push(entry);
    }
  }
}

// Assign source_type basierend auf URL-Pattern
for (const s of allSources) {
  if (!s.source_type || s.source_type === 'web') {
    const url = s.url.toLowerCase();
    if (url.includes('arxiv.org') || url.includes('scholar.google') || url.includes('doi.org')) {
      s.source_type = 'academic';
      s.tier = 'T1';
    } else if (url.includes('reddit.com') || url.includes('x.com') || url.includes('twitter.com')) {
      s.source_type = 'social';
    } else if (url.includes('youtube.com') || url.includes('youtu.be')) {
      s.source_type = 'youtube';
    }
  }
  // Cross-referenced sources get a tier boost
  if (s.cross_referenced && s.tier === 'T3') {
    s.tier = 'T2';
  }
}

// Sortieren nach Relevanz
allSources.sort((a, b) => b.relevance_score - a.relevance_score);

// Statistiken
const platforms = new Set(allSources.map(s => s.origin.split('+')[0]));
const stats = {
  total_sources: allSources.length,
  unique_platforms: platforms.size,
  platforms: [...platforms],
  by_tier: {
    T1: allSources.filter(s => s.tier === 'T1').length,
    T2: allSources.filter(s => s.tier === 'T2').length,
    T3: allSources.filter(s => s.tier === 'T3').length
  },
  cross_referenced: allSources.filter(s => s.cross_referenced).length
};

return [{ json: { sources: allSources, stats } }];

// Basic claim extraction — extract key statements from sources
const { sources, stats } = $input.first().json;
const claims = [];

for (const source of sources) {
  const snippet = source.snippet || '';
  if (!snippet || snippet.length < 30) continue;

  // Einfache Satz-Extraktion: Saetze die faktische Aussagen enthalten
  const sentences = snippet
    .replace(/\s+/g, ' ')
    .split(/(?<=[.!?])\s+/)
    .filter(s => s.length > 30 && s.length < 500);

  for (const sentence of sentences.slice(0, 3)) {
    // Filter fuer Aussagen die wie Claims klingen
    // (enthalten Zahlen, Vergleiche, definitive Aussagen)
    const isLikelyClaim = /\d/.test(sentence) ||
      /(?:is|are|was|were|has|have|will|can|should|must|shows?|proves?|indicates?|according|found|reported|announced|launched|released)/i.test(sentence) ||
      /(?:ist|sind|war|hat|wird|kann|soll|muss|zeigt|beweist|laut|ergab|berichtet)/i.test(sentence);

    if (isLikelyClaim) {
      claims.push({
        text: sentence.trim(),
        source_url: source.url,
        source_title: source.title,
        source_type: source.source_type,
        confidence: 0.0,
        cove_status: null,
        final_status: 'pending'
      });
    }
  }
}

// Dedupliziere aehnliche Claims (exakte Duplikate)
const uniqueClaims = [];
const seenTexts = new Set();
for (const claim of claims) {
  const normalized = claim.text.toLowerCase().replace(/\s+/g, ' ').trim();
  if (!seenTexts.has(normalized)) {
    seenTexts.add(normalized);
    uniqueClaims.push(claim);
  }
}

return [{
  json: {
    sources,
    claims: uniqueClaims,
    stats: {
      ...stats,
      total_claims: uniqueClaims.length,
      claims_from_sources: new Set(uniqueClaims.map(c => c.source_url)).size
    }
  }
}];
